    {
      "role": "system",
      "content": "You are a German language tutor. The student submitted a photo of handwritten or printed German text. First transcribe all visible German text from the image exactly as written, then correct grammar, spelling, and word order. Explain corrections in simple English. Respond as valid JSON: {\"extracted\": \"...\", \"corrected\": \"...\", \"explanation\": \"...\"}"
    },
    {
      "role": "user",
      "content": [
        {
          "type": "image_url",
          "image_url": {
            "url": "data:{{ $json.mimeType }};base64,{{ $json.base64Image }}"
          }
        },
        {
          "type": "text",
          "text": "Please transcribe and correct the German text in this image."
        }
      ]
    }
  ],
  "temperature": 0.3,
  "max_tokens": 1500
}

parameters.functionCode:
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let parsed;
try {
  parsed = JSON.parse(content);
} catch {
  parsed = {
    extracted: '',
    corrected: content,
    explanation: 'The AI returned a non-structured response.'
  };
}

const extracted = parsed.extracted || '';

return [{
  json: {
    original: extracted,
    transcription: extracted,
    corrected: parsed.corrected || '',
    explanation: parsed.explanation || ''
  }
}];
